async function handlePaymentEvent(payment) {
  switch (payment.eventType) {
    case 'payment.created':
      return await processPaymentCreated(payment);
    case 'payment.captured':
      return await processPaymentCaptured(payment);
    case 'payment.refunded':
      return await processPaymentRefunded(payment);
    case 'payment.cancelled':
      return await processPaymentCancelled(payment);
    default:
      throw new Error(`Unhandled event type: ${payment.eventType}`);
  }
}

function getRetryCount(msg) {
  const deaths = msg.properties.headers && msg.properties.headers['x-death'];
  if (!deaths || deaths.length === 0) return 0;
  return deaths.reduce((count, death) => count + (death.count || 0), 0);
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set up dead letter exchange for failed messages
    await channel.assertExchange('payment_dlx', 'direct', { durable: true });
    await channel.assertQueue(DEAD_LETTER_QUEUE, {
      durable: true,
    });
    await channel.bindQueue(DEAD_LETTER_QUEUE, 'payment_dlx', QUEUE_NAME);

    // Set up main queue with dead letter routing
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'payment_dlx',
        'x-dead-letter-routing-key': QUEUE_NAME,
      },
    });

    // Process one message at a time for payment safety
    await channel.prefetch(1);

    console.log(`Payment consumer started. Waiting for messages on queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const messageId = msg.properties.messageId || 'unknown';
      const correlationId = msg.properties.correlationId || 'unknown';

      try {
        // Step 1: Verify message signature
        const signature = msg.properties.headers && msg.properties.headers['x-signature'];
        if (!verifyMessageSignature(msg.content, signature)) {
          console.error(
            `SECURITY: Message signature verification FAILED. messageId=${messageId}, correlationId=${correlationId}. Rejecting without requeue.`
          );
          // Do NOT requeue - this is a security issue, send to DLQ for investigation
          channel.nack(msg, false, false);
          return;
        }

        // Step 2: Parse message
        let payment;
        try {
          payment = JSON.parse(msg.content.toString());
        } catch (parseError) {
          console.error(`Failed to parse message content. messageId=${messageId}`, parseError.message);
          channel.nack(msg, false, false);
          return;
        }

        // Step 3: Validate message structure and content
        validatePaymentMessage(payment);

        // Step 4: Check for idempotency (in production, check against a database/cache)
        console.log(
          `Verified message received: eventType=${payment.eventType}, paymentId=${payment.paymentId}, messageId=${messageId}`
        );

        // Step 5: Process the payment event
        const result = await handlePaymentEvent(payment);

        console.log(
          `Payment event processed successfully: paymentId=${payment.paymentId}, result=${JSON.stringify(result)}`
        );

        // Acknowledge successful processing
        channel.ack(msg);
      } catch (error) {
        const retryCount = getRetryCount(msg);
        console.error(
          `Error processing payment message. messageId=${messageId}, retryCount=${retryCount}, error=${error.message}`
        );

        if (retryCount >= MAX_RETRIES) {
          console.error(
            `Max retries (${MAX_RETRIES}) exceeded for messageId=${messageId}. Sending to DLQ.`
          );
          channel.nack(msg, false, false); // Send to DLQ
        } else {
          console.log(`Requeueing message messageId=${messageId} for retry.`);
          channel.nack(msg, false, true); // Requeue for retry
        }
      }
    });

    // Handle connection errors
    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.warn('RabbitMQ connection closed. Attempting to reconnect in 5 seconds...');
      setTimeout(startConsumer, 5000);
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`Received ${signal}. Shutting down gracefully...`);
      try {
        await channel.close();
        await connection.close();
      } catch (err) {
        console.error('Error during shutdown:', err.message);
      }
      process.exit(0);
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));
  } catch (error) {
    console.error('Failed to start payment consumer:', error.message);
    if (channel) {
      try { await channel.close(); } catch (_) {}
    }
    if (connection) {
      try { await connection.close(); } catch (_) {}
    }
    console.log('Retrying connection in 5 seconds...');
    setTimeout(startConsumer, 5000);
  }
}

